import json
from pathlib import Path
from typing import Any, Dict, List, Optional


class Note:
    """
    Represents a single knowledge asset (Note) within the Second Brain.
    Ensures data encapsulation and clean serialization interfaces.
    """

    def __init__(self, title: str, content: str, tags: Optional[List[str]] = None) -> None:
        self.title: str = title.strip()
        self.content: str = content
        self.tags: List[str] = tags or []

        if not self.title:
            raise ValueError("Note title cannot be empty or whitespace-only.")

    def to_dict(self) -> Dict[str, Any]:
        """Serializes the Note instance to a dictionary."""
        return {
            "title": self.title,
            "content": self.content,
            "tags": self.tags
        }

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "Note":
        """Factory method to instantiate a Note from a dictionary representation."""
        return cls(
            title=data.get("title", ""),
            content=data.get("content", ""),
            tags=data.get("tags", [])
        )


class SecondBrain:
    """
    Manages the lifecycle, persistence, and querying of Notes.
    Acts as the primary interface for the Second Brain system.
    """

    def __init__(self, storage_path: str = "second_brain_store.json") -> None:
        self.storage_path: Path = Path(storage_path)
        self.notes: Dict[str, Note] = {}
        self._load_notes()

    def add_note(self, title: str, content: str, tags: Optional[List[str]] = None) -> Note:
        """Creates, stores, and persists a new note."""
        note = Note(title=title, content=content, tags=tags)
        self.notes[note.title] = note
        self._save_notes()
        return note

    def get_note(self, title: str) -> Optional[Note]:
        """Retrieves a note by its exact title match."""
        return self.notes.get(title.strip())

    def search_by_tag(self, tag: str) -> List[Note]:
        """Filters and returns all notes containing the specified tag."""
        normalized_tag = tag.strip().lower()
        return [
            note for note in self.notes.values()
            if any(t.lower() == normalized_tag for t in note.tags)
        ]

    def _load_notes(self) -> None:
        """
        Loads notes from the persistent JSON storage.

        If the file does not exist, initializes an empty state safely.
        If the file exists but contains invalid JSON, wrong structural schemas, 
        or faces permission locks, it propagates a descriptive exception to 
        prevent silent state overwrites and catastrophic user data loss.
        """
        if not self.storage_path.exists():
            self.notes = {}
            return

        try:
            with open(self.storage_path, "r", encoding="utf-8") as file:
                raw_data = json.load(file)
        except Exception as e:
            raise RuntimeError(
                f"Failed to read or parse Second Brain storage file at {self.storage_path}: {e}"
            ) from e

        # Validate that the JSON root element is a dictionary
        if not isinstance(raw_data, dict):
            raise TypeError(
                f"Invalid storage schema in {self.storage_path}: Expected a root dictionary, got {type(raw_data).__name__}."
            )

        loaded_notes: Dict[str, Note] = {}
        for title, note_data in raw_data.items():
            # Validate that each note entry is a dictionary schema
            if not isinstance(note_data, dict):
                raise TypeError(
                    f"Invalid schema for note '{title}': Expected a dictionary, got {type(note_data).__name__}."
                )

            try:
                loaded_notes[title] = Note.from_dict(note_data)
            except Exception as e:
                raise ValueError(
                    f"Failed to deserialize note payload for '{title}': {e}"
                ) from e

        self.notes = loaded_notes

    def _save_notes(self) -> None:
        """Persists the current in-memory notes to the JSON storage file."""
        try:
            with open(self.storage_path, "w", encoding="utf-8") as file:
                serialized_data = {title: note.to_dict() for title, note in self.notes.items()}
                json.dump(serialized_data, file, indent=4, ensure_ascii=False)
        except IOError as e:
            raise RuntimeError(f"Failed to persist Second Brain storage: {e}")
